declare namespace Markdown {
  /** Protocol FIELDS */
  /**
   * step - research step
   *
   * var - research variable
   *
   * rr - research result
   *
   * rn - ResearchNode
   *
   * rnc - research chain
   *
   * rrec - research record
   *
   * rp - research protocol
   *
   * rnw - protocol workflow
   */
  type FiledName = "step" | "var" | "rr" | "rn" | "check" | "rrec" | "rp" | "rq" | "rnw" | "step_ref"
}
